package pe.edu.utp.tmo.service.impl;
import org.springframework.security.authentication.BadCredentialsException; import org.springframework.security.crypto.password.PasswordEncoder; import org.springframework.stereotype.Service; import pe.edu.utp.tmo.dao.UsuarioDAO; import pe.edu.utp.tmo.dto.request.LoginRequest; import pe.edu.utp.tmo.dto.response.AuthResponse; import pe.edu.utp.tmo.model.entity.Usuario; import pe.edu.utp.tmo.security.JwtService; import pe.edu.utp.tmo.service.AuthService; import pe.edu.utp.tmo.util.ValidationUtils;
@Service public class AuthServiceImpl implements AuthService{ private final UsuarioDAO dao; private final PasswordEncoder enc; private final JwtService jwt; public AuthServiceImpl(UsuarioDAO dao,PasswordEncoder enc,JwtService jwt){this.dao=dao;this.enc=enc;this.jwt=jwt;} public AuthResponse login(LoginRequest r){String c=ValidationUtils.correo(r.correo()); Usuario u=dao.buscarPorCorreo(c).orElseThrow(()->new BadCredentialsException("Credenciales inválidas")); if(!u.isActivo()||!enc.matches(r.password(),u.getPasswordHash())) throw new BadCredentialsException("Credenciales inválidas"); return new AuthResponse(jwt.generarToken(u),u.getRol().name(),u.getNombres(),u.getArea(),jwt.expira());}}
